import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const Dashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    total: 0, pending: 0, closed: 0, assigned: 0, inProgress: 0, onHold: 0,
  });
  const [userRole, setUserRole] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const role = localStorage.getItem('role');
    setUserRole(role);
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const { data } = await API.get('/complaints/stats');
      setStats({
        total: data.total || 0,
        pending: data.pending || 0,
        assigned: data.assigned || 0,
        inProgress: data.inProgress || 0,
        onHold: data.onHold || 0,
        closed: data.closed || 0,
      });
    } catch (err) {
      console.error('Error fetching stats:', err);
    } finally {
      setLoading(false);
    }
  };

  const go = (path) => navigate(path);

  const isAdmin = userRole === 'SuperAdmin' || userRole === 'Admin';
  const isUser = userRole === 'User';
  const techRoles = ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer', 'Cleaner', 'Carpenter'];
  const isTech = techRoles.includes(userRole);

  return (
    <div className="page-wrapper">
      <Navigation />

      <div className="content-area">
        <div className="header-section">
          <h1 className="main-title">Dashboard</h1>
          <p className="subtitle">Welcome to your Ticket Management System</p>
        </div>

        {/* Stats */}
        {!loading && (
          <div className="section">
            <h2 className="section-title">📊 Complaint Statistics</h2>
            <div className="stats-grid">
              {isUser ? (
                <>
                  <StatCard icon="📋" label="Total Complaints" value={stats.total} color="#6366f1" />
                  <StatCard icon="⏱️" label="Pending" value={stats.pending} color="#f59e0b" />
                  <StatCard icon="✅" label="Completed" value={stats.closed} color="#10b981" />
                </>
              ) : (
                <>
                  <StatCard icon="📋" label="Total Tickets" value={stats.total} color="#6366f1" />
                  <StatCard icon="⏱️" label="Pending" value={stats.pending} color="#f59e0b" />
                  <StatCard icon="👤" label="Assigned" value={stats.assigned} color="#8b5cf6" />
                  <StatCard icon="⚙️" label="In Progress" value={stats.inProgress} color="#3b82f6" />
                  <StatCard icon="🔒" label="On Hold" value={stats.onHold} color="#ef4444" />
                  <StatCard icon="✅" label="Completed" value={stats.closed} color="#10b981" />
                </>
              )}
            </div>
          </div>
        )}

        {/* Admin Controls */}
        {isAdmin && (
          <div className="section">
            <div className="section-header">
              <span className="section-icon">🔐</span>
              <h2 className="section-title">Admin Controls</h2>
            </div>
            <div className="buttons-grid">
              <NavBtn icon="🏢" label="Department Master" onClick={() => go('/department')} />
              <NavBtn icon="📚" label="Programme Master" onClick={() => go('/programme')} />
              <NavBtn icon="🏠" label="Block Master" onClick={() => go('/block')} />
              <NavBtn icon="🚪" label="Room Master" onClick={() => go('/room')} />
              <NavBtn icon="👑" label="Role Master" onClick={() => go('/role')} />
              <NavBtn icon="👥" label="User Management" onClick={() => go('/users')} />
            </div>
          </div>
        )}

        {/* Ticket Management */}
        <div className="section">
          <div className="section-header">
            <span className="section-icon">🎫</span>
            <h2 className="section-title">Ticket Management</h2>
          </div>
          <div className="buttons-grid">
            {(isUser || isAdmin) && (
              <NavBtn icon="📝" label="Raise New Ticket" onClick={() => go('/raise-complaint')} primary />
            )}
            <NavBtn icon="📋" label={isAdmin ? "View All Tickets" : "View My Tickets"} onClick={() => go('/complaints')} />
            {isAdmin && (
              <NavBtn icon="📈" label="Generate Report" onClick={() => go('/report')} primary />
            )}
          </div>
        </div>

        {/* User Quick Instructions - Only for regular users */}
        {isUser && (
          <div className="section">
            <div className="section-header">
              <span className="section-icon">📖</span>
              <h2 className="section-title">How to use TMS</h2>
            </div>
            <div className="glass-card instruction-card">
              <div className="instruction-item">
                <span className="step-badge">1</span>
                <div>
                  <h4>Raise a New Ticket</h4>
                  <p>Click the <strong>'Raise New Ticket'</strong> button to report any infrastructure or maintenance issues.</p>
                </div>
              </div>
              <div className="instruction-item">
                <span className="step-badge">2</span>
                <div>
                  <h4>Provide Precise Details</h4>
                  <p>Mention the correct <strong>Block and Room Number</strong> so our staff can locate the problem quickly.</p>
                </div>
              </div>
              <div className="instruction-item">
                <span className="step-badge">3</span>
                <div>
                  <h4>Track Progress</h4>
                  <p>Go to <strong>'View My Tickets'</strong> to see the current status of your requests (Pending, Assigned, or Completed).</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const StatCard = ({ icon, label, value, color }) => (
  <div className="stat-card" style={{ '--stat-color': color }}>
    <span className="stat-icon">{icon}</span>
    <div className="stat-label">{label}</div>
    <div className="stat-value">{value}</div>
  </div>
);

const NavBtn = ({ icon, label, onClick, primary = false }) => (
  <button onClick={onClick} className={`btn-nav ${primary ? 'btn-nav-primary' : ''}`}>
    <span className="btn-icon">{icon}</span>
    <span>{label}</span>
  </button>
);

export default Dashboard;
